const latePlan = getArchiveRecordGroupPlan('late');
if (!latePlan || latePlan.length !== LATE_RECORD_CONTENT.length) {
  throw new Error('Late archive record content does not match the canonical twenty-slot plan.');
}

export const ARCHIVE_RECORDS_LATE = deepFreeze(latePlan.map((slot, index) => ({
  id: slot.id,
  sequence: slot.sequence,
  chapterId: slot.chapterId,
  unlockAfterBeatId: slot.unlockAfterBeatId,
  title: LATE_RECORD_CONTENT[index].title,
  recordType: LATE_RECORD_CONTENT[index].recordType,
  custodian: LATE_RECORD_CONTENT[index].custodian,
  accessNote: LATE_RECORD_CONTENT[index].accessNote,
  paragraphs: LATE_RECORD_CONTENT[index].paragraphs,
})));

export const ARCHIVE_RECORDS_LATE_VALIDATION = validateArchiveRecordPack(ARCHIVE_RECORDS_LATE, {
  expectedGroup: 'late',
});

if (!ARCHIVE_RECORDS_LATE_VALIDATION.ok) {
  throw new Error(`Invalid late archive records:\n${ARCHIVE_RECORDS_LATE_VALIDATION.errors.join('\n')}`);
}
